VALUES
  ('heelevel3-d0d1b9a2-moex-00515', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司以直接人工小時為基礎分攤製造費用。某年度公司之預計製造費用為$172,140，實際 製造費用為$171,000；預計直接人工小時數為3,800小時，實際人工小時數為3,880小時。試 問當年度多分攤製造費用的金額為何？', '["多分攤製造費用$4,764", "多分攤製造費用$3,600", "多分攤製造費用$1,156", "多分攤製造費用$1,140"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "4b3e125ac1b5", "answer_pdf_sha1": "f3b54cbf9472", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00516', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', 'A公司採分步成本制，正常損壞為完好產品的8%，公司的檢驗點於完工50%時進行。7月份 期初在製品為2,000單位，完工程度為40%，期末在製品為1,500單位，完工程度為60%。7 月投入生產5,000單位，完工並轉出之完好品有4,500單位，7月份非常損壞單位數為何？', '["480", "520", "600", "680"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "4b3e125ac1b5", "answer_pdf_sha1": "f3b54cbf9472", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00517', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '某公司販售多種商品，平均收入及成本資料如下： 每單位售價：$50 每單位變動成本：直接材料$10 直接製造人工$5 製造費用$3 銷售成本$5 每年固定成本$200,000 當年販售15,000個商品 假設直接材料及直接製造人工各增加$2，則對邊際貢獻有何影響？', '["增加$30,000", "增加$60,000", "減少$30,000", "減少$60,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "4b3e125ac1b5", "answer_pdf_sha1": "f3b54cbf9472", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00518', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', 'A公司本月的直接原料呈現有利的價格差異，請問下列何者為可能原因？', '["採購經理的議價能力佳", "採購經理大量購買原料", "採購經理改用高品質的直接原料", "直接原料市場供不應求 ⑤預算直接原料購買價格設定太高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "4b3e125ac1b5", "answer_pdf_sha1": "f3b54cbf9472", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00519', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '某公司X9年甲、乙兩項產品預計及實際銷售資料如下： 甲產品 乙產品 預計 實際 預計 實際 銷售單位 1,800 2,100 3,600 5,100 單位毛利 $24 $22 $48 $50 試問該公司X9年之銷售組合差異為何？', '["甲產品$7,200（不利），乙產品$14,400（有利）", "甲產品$14,400（有利），乙產品$57,600（有利）", "甲產品$7,200（有利），乙產品$72,000（有利）", "甲產品$11,400（不利），乙產品$24,600（有利）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "4b3e125ac1b5", "answer_pdf_sha1": "f3b54cbf9472", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00520', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司考慮是否購買一台新機器，取得成本$1,380,000，預估未來淨現金流量如下： 淨現金流量 第1年 $276,000 第2年 575,000 第3年 253,000 第4年 184,000 第5年 368,000 若甲公司採用還本期間法，此決策不應考慮下列何項資訊？', '["機會成本", "付現成本", "沉沒成本", "可免成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "4b3e125ac1b5", "answer_pdf_sha1": "f3b54cbf9472", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00521', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲批發商於上個月以每公斤$50 進貨 5,200 公斤果乾一批，近月來果乾市價不斷上揚至每公 斤$65。該批發商收到乙零售商特殊訂單2,000公斤。甲批發商在考慮是否接受此特殊訂單時， 下列何者為攸關資訊？', '["上月每公斤$50採購價", "現時每公斤$65市價", "上月進貨5,200公斤", "一般訂單客戶對此特殊訂單看法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "4b3e125ac1b5", "answer_pdf_sha1": "f3b54cbf9472", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00522', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司生產電子零件，該公司每月的產能為12,000單位，目前該公司每月產銷10,000單位， 公司售價採製造成本加成30%。有關該公司目前之作業水準之成本資訊如下： 產出單位 10,000 單位 直接製造人工小時 5,000小時 機器小時 8,000 小時 直接材料每單位 $25 直接製造人工每小時 $14 變動製造費用每機器小時 $20 固定製造費用 $120,000 固定行銷費用 $60,000 目前該公司收到一次性的訂單，數量為 2,000 單位。公司若接受此一特殊訂單並不影響正常 銷售，也將不會發生額外的行銷費用，但須額外花一筆運送費用 $4,000，試問每單位公司最 低可接受的報價為何？', '["$50", "$60", "$65", "$78"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "4b3e125ac1b5", "answer_pdf_sha1": "f3b54cbf9472", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00523', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司為一家汽車修理廠，依據直接人工成本加價 100%與直接材料成本加價 50%的方式向 客戶報價，該公司每小時人工成本為$50。假設某台車輛經檢查後，該公司提供了「修理不換 零件」與「更換零件」兩種方式供客戶選擇，此兩方案之成本資訊如下： 人工 材料 修理不換零件 4小時 $60 更換零件 2小時 $220 試問下列何種情況公司會建議客戶更換零件？', '["當公司的目標是追求較高的公司利潤", "當公司的目標是追求較高的每單位時間利潤", "當公司的目標是追求較高的毛利率", "當公司的目標是追求較高的主要成本加成百分比"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "4b3e125ac1b5", "answer_pdf_sha1": "f3b54cbf9472", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00524', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-110-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司為一提供人力的合約商，主要提供大樓建築公司人工合約。該公司之人工合約為每小 時的變動成本為$15，總固定成本為$336,000，公司採用全部成本加20%作為訂價，根據過去 的經驗各需求小時與發生的機率如下： 需求小時數 發生的機率 80,000 25% 70,000 50% 60,000 25% 在上述需求範圍內，總固定成本將維持不變，則公司每小時報價的期望值為何？', '["$23.04", "$23.76", "$23.82", "$24.72"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:02+00:00", "source_pdf_sha1": "4b3e125ac1b5", "answer_pdf_sha1": "f3b54cbf9472", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "326", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
